    source: `${PEND_SRC} — MC-PENDULUM-PERIOD-DEPENDS-ON-MASS (mass cancels, equivalence principle) + MC-PENDULUM-AMPLITUDE-CHANGES-PERIOD (isochronism for small angles)`,
