// ─── phys.mech.hamiltons-equations ─────────────────────────────────────────────
const HAMQ = 'phys.mech.hamiltons-equations'
const HAMQ_SRC = 'docs/curriculum/blueprints/phys.mech.hamiltons-equations.md'

